import sys
from collections import deque

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    graph = input[1:]

    # Preprocess the graph into a 2D list
    edges = [[-1 for _ in range(N)] for _ in range(N)]
    for i in range(N):
        for j in range(N):
            c = graph[i][j]
            if c != '-':
                edges[i][j] = ord(c) - ord('a')

    # Initialize the result matrix
    result = [[-1 for _ in range(N)] for _ in range(N)]

    for i in range(N):
        for j in range(N):
            if i == j:
                result[i][j] = 0
                continue

            # BFS for the (i, j) pair
            dist = [[-1 for _ in range(N)] for _ in range(N)]
            q = deque()
            dist[i][j] = 0
            q.append((i, j))

            while q:
                u, v = q.popleft()
                # Try all possible edges from u and v with the same label
                for l in range(26):
                    # Find all edges from u with label l
                    for w in range(N):
                        if edges[u][w] == l:
                            # Find all edges from v with label l
                            for x in range(N):
                                if edges[v][x] == l:
                                    if dist[w][x] == -1:
                                        dist[w][x] = dist[u][v] + 2
                                        q.append((w, x))

            # Find the minimal steps to reach (u, u)
            min_len = -1
            for u in range(N):
                if dist[u][u] != -1:
                    if min_len == -1 or dist[u][u] < min_len:
                        min_len = dist[u][u]

            result[i][j] = min_len if min_len != -1 else -1

    # Print the result
    for row in result:
        print(' '.join(map(str, row)))

