def main():
    sys.setrecursionlimit(1 << 25)
    N = int(sys.stdin.readline())
    S = sys.stdin.readline().strip()
    T = sys.stdin.readline().strip()

    # Check if S and T are already equal
    if S == T:
        print(0)
        return

    # Create mapping from S to T
    mapping = {}
    valid = True
    for s_char, t_char in zip(S, T):
        if s_char in mapping:
            if mapping[s_char] != t_char:
                valid = False
                break
        else:
            mapping[s_char] = t_char

    if not valid:
        print(-1)
        return

    # Build the graph
    graph = defaultdict(list)
    nodes = set(mapping.keys())
    for char in nodes:
        graph[char].append(mapping[char])

    # Check for cycles in the graph
    visited = set()
    recursion_stack = set()

    def has_cycle(node):
        if node in recursion_stack:
            return True
        if node in visited:
            return False
        visited.add(node)
        recursion_stack.add(node)
        for neighbor in graph[node]:
            if has_cycle(neighbor):
                return True
        recursion_stack.remove(node)
        return False

    for node in nodes:
        if node not in visited:
            if has_cycle(node):
                print(-1)
                return

    # Calculate number of roots (nodes where mapping[x] == x)
    roots = 0
    for node in nodes:
        if mapping[node] == node:
            roots += 1

    # The number of operations is number of nodes - number of roots
    num_nodes = len(nodes)
    print(num_nodes - roots)

