MOD = 998244353

def main():
    import sys
    input = sys.stdin.read
    W, H, L, R, D, U = map(int, input().split())

    # Precompute allowed regions
    allowed = set()
    for x in range(W+1):
        for y in range(H+1):
            if (x < L) or (R < x) or (y < D) or (U < y):
                allowed.add((x, y))

    # Initialize a dictionary to store dp values
    dp = {}

    # Process from bottom-right to top-left
    for x in range(W, -1, -1):
        for y in range(H, -1, -1):
            if (x, y) in allowed:
                right = 0
                if x + 1 <= W and (x+1, y) in allowed:
                    right = dp.get((x+1, y), 0)
                up = 0
                if y + 1 <= H and (x, y+1) in allowed:
                    up = dp.get((x, y+1), 0)
                dp[(x, y)] = (1 + right + up) % MOD
            else:
                dp[(x, y)] = 0

    # Sum all dp values
    total = 0
    for (x, y) in allowed:
        total = (total + dp[(x, y)]) % MOD

    print(total)

