class Solution:
    def zigzagTraversal(self, grid: List[List[int]]) -> List[int]:
        result = []
        for i in range(len(grid)):
            if i % 2 == 0:
                # Even row: take every other cell starting from index 0
                result.extend(grid[i][::2])
            else:
                # Odd row: take every other cell starting from index 1
                result.extend(grid[i][1::2])
        return result

class Solution:
    def maximumAmount(self, coins: List[List[int]]) -> int:
        m = len(coins)
        n = len(coins[0])
        INF = float('-inf')
        dp = [[[INF for _ in range(3)] for __ in range(n)] for ___ in range(m)]

        # Initialize the first cell (0,0)
        if coins[0][0] >= 0:
            for k in range(3):
                dp[0][0][k] = coins[0][0]
        else:
            dp[0][0][0] = coins[0][0]
            dp[0][0][1] = 0
            dp[0][0][2] = INF

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                # Compute temp array for not neutralizing
                temp = [INF] * 3
                for k in range(3):
                    prev_max = INF
                    if i > 0:
                        prev_max = max(prev_max, dp[i-1][j][k])
                    if j > 0:
                        prev_max = max(prev_max, dp[i][j-1][k])
                    if coins[i][j] >= 0:
                        temp[k] = prev_max + coins[i][j]
                    else:
                        temp[k] = prev_max + coins[i][j]
                # If the cell is a robber, process neutralizing
                if coins[i][j] < 0:
                    for k in range(3):
                        if k < 2:
                            prev_max2 = INF
                            if i > 0:
                                prev_max2 = max(prev_max2, dp[i-1][j][k+1])
                            if j > 0:
                                prev_max2 = max(prev_max2, dp[i][j-1][k+1])
                            if prev_max2 != INF:
                                temp[k+1] = max(temp[k+1], prev_max2 + 0)
                # Set the dp[i][j][k] to temp[k]
                for k in range(3):
                    dp[i][j][k] = temp[k]

        return max(dp[m-1][n-1][0], dp[m-1][n-1][1], dp[m-1][n-1][2])

