class Solution:
    def minMaxWeight(self, n: int, edges: List[List[int]], threshold: int) -> int:
        # Find the maximum edge weight
        max_w = max(e[2] for e in edges)
        low = 1
        high = max_w
        answer = -1

        def is_possible(mid):
            # Build reversed graph
            rev_adj = [[] for _ in range(n)]
            for u, v, w in edges:
                if w <= mid:
                    rev_adj[v].append(u)
            # BFS to check if all nodes can reach 0 in original graph
            visited = [False] * n
            queue = deque([0])
            visited[0] = True
            while queue:
                node = queue.popleft()
                for neighbor in rev_adj[node]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        queue.append(neighbor)
            # Check all nodes are visited
            for i in range(n):
                if not visited[i]:
                    return False
            return True

        while low <= high:
            mid = (low + high) // 2
            if is_possible(mid):
                answer = mid
                high = mid - 1
            else:
                low = mid + 1
        return answer if answer != -1 else -1

