class Solution:
    def countNonDecreasingSubarrays(self, nums: List[int], k: int) -> int:
        n = len(nums)
        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]

        dq = deque()
        left = 0
        ans = 0

        for right in range(n):
            # Maintain the deque for the current window [left, right]
            while dq and nums[right] >= nums[dq[-1]]:
                dq.pop()
            dq.append(right)

            # Adjust the left pointer to ensure the required operations are within k
            while True:
                # Remove elements from the front of the deque that are out of the current window
                while dq and dq[0] < left:
                    dq.popleft()

                if not dq:
                    break

                current_max = nums[dq[0]]
                current_length = right - left + 1
                current_sum = prefix_sum[right + 1] - prefix_sum[left]
                required_ops = current_max * current_length - current_sum

                if required_ops <= k:
                    break
                else:
                    left += 1

            ans += (right - left + 1)

        return ans

