class Solution:
    def minCost(self, n: int, cost: List[List[int]]) -> int:
        m = n // 2
        INF = float('inf')
        prev_dp = [[INF] * 3 for _ in range(3)]

        # Initialize for the first pair (houses 0 and n-1)
        for c_i in range(3):
            for c_j in range(3):
                if c_i != c_j:
                    prev_dp[c_i][c_j] = cost[0][c_i] + cost[n-1][c_j]

        # Process remaining pairs
        for k in range(1, m):
            current_dp = [[INF] * 3 for _ in range(3)]
            # Current pair is (k, n-1 -k)
            for c_i in range(3):
                for c_j in range(3):
                    if c_i == c_j:
                        continue
                    # Check all previous states
                    for prev_i in range(3):
                        for prev_j in range(3):
                            if prev_dp[prev_i][prev_j] != INF:
                                if prev_i != c_i and prev_j != c_j:
                                    current_val = prev_dp[prev_i][prev_j] + cost[k][c_i] + cost[n-1 - k][c_j]
                                    if current_val < current_dp[c_i][c_j]:
                                        current_dp[c_i][c_j] = current_val
            prev_dp = current_dp

        # Find the minimum value in the last DP matrix
        res = INF
        for row in prev_dp:
            res = min(res, min(row))
        return res

